class Solution:
    def missingMultiple(self, nums, k):
        present = set(nums)
        m = k
        while m in present:
            m += k
        return m

solutions.javascript:
var missingMultiple = function(nums, k) {
    const present = new Set(nums);
    let m = k;
    while (present.has(m)) m += k;
    return m;
};
